INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-f7485f85-moex-00051', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-13504c0c', 'sub-aboriginal-f7485f85-03', NULL, 'single_choice', '下列文句「 」中的成語，何者運用最恰當？', '["這家店物美價廉，即使沒有廣告，聲譽也能「不脛而走」", "小華每次都到了考前才「緣木求魚」，難怪成績慘不忍睹", "小明雖然自謙他的意見是「滄海一粟」，但其實頗有價值", "這個月開銷太大，還沒月底就左支右絀、「臨渴掘井」了"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "2d4a2c95a108", "answer_pdf_sha1": "f6341680c20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00052', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-13504c0c', 'sub-aboriginal-f7485f85-03', NULL, 'single_choice', '周先生參觀書法展，事後撰文評論參展作品。下列詞語，何者形容有誤？', '["筆勢跌宕縱橫", "用筆吞吐抑揚", "字字鐵畫銀鉤", "筆法朱墨爛然"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "2d4a2c95a108", "answer_pdf_sha1": "f6341680c20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00053', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-13504c0c', 'sub-aboriginal-f7485f85-03', NULL, 'single_choice', '「在1909年到1910年之間，柯克西卡（1886-1980）畫了一系列超乎尋常、充滿爆 炸性的肖像與人物畫，他將過去在雕塑中使用的手法轉用到畫布上：多重劃痕、拇 指作畫，以及不自然的顏色。這類人物畫嚴重偏離當代口味，那是已經由克林姆 （1862-1918）所建立的漂亮裝飾之女性畫像。柯克西卡的頭雕、人物畫，與他在這 個時期所寫的兩齣表現主義劇本，將維也納社會推入混亂之中。他的肖像人物畫， 代表了維也納現代主義繪畫技法演進過程上的巨幅跳躍。就像克林姆與過去決裂， 放棄了數百年的錯覺藝術，而且將拜占庭藝術的平坦性帶入現代藝術，柯克西卡則 藉著融合風格主義對形狀與色彩的誇張表現，與原始藝術以及卡通技法，來與當代 作一決裂。」 根據上文，下列選項何者最符合柯克西卡的描述？', '["肖像人物畫的技法與風格，主要是承襲前輩畫家克林姆所建立的漂亮裝飾之女性畫像", "與克林姆對於現代繪畫藝術的貢獻，是他們都在各自所處的位置做了超越當代的突破", "擅長的多重劃痕、拇指作畫，以及不自然的顏色技法，是與雕塑創作精神上的一 種決裂", "擅長肖像畫，創作前期是維也納現代主義技法演進上的微幅提升，後期則是巨幅跳躍"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "2d4a2c95a108", "answer_pdf_sha1": "f6341680c20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00054', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-13504c0c', 'sub-aboriginal-f7485f85-03', NULL, 'single_choice', '「韓非認為：君主一個人的思慮有限，單憑有限的智識，不能完全掌握所有事物，所 以強調應『分層負責』」。下列《韓非子》中的文句，最能印證前述觀點的是：', '["官職所以任賢也，爵祿所以賞功也", "明主之吏，宰相必起於州部，猛將必發於卒伍", "設官職，陳爵祿，而士自至，君人者奚其勞哉！使人又非所佚也", "人主使人臣，雖有智能，不得背法而專制；雖有賢行，不得踰功而先勞"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "2d4a2c95a108", "answer_pdf_sha1": "f6341680c20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00055', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-13504c0c', 'sub-aboriginal-f7485f85-03', NULL, 'single_choice', '嘗謂獨也者，君子與小人共焉者也。小人以其為獨而生一念之妄，積妄生肆，而欺 人之事成。君子懍其為獨而生一念之誠，積誠為慎，而自謙之功密。其間離合幾微 之端，可得而論矣。（曾國藩〈君子慎獨論〉） 根據上文，下列敘述何者錯誤？', '["君子與小人之別在於如何慎獨", "君子與小人慎獨之別在於一念之間", "君子獨處利於積誠，小人獨處易於放肆", "君子與小人皆怕獨處，易令人滋生妄念"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "2d4a2c95a108", "answer_pdf_sha1": "f6341680c20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00056', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-13504c0c', 'sub-aboriginal-f7485f85-03', NULL, 'single_choice', '「忙起來時，一天過去都沒機會往沙發上靠一下。一回家就得趕快整理剛買回的菜 料、替孩子洗手換衣。幸好沙發是敦厚的，永遠弓著飽滿身軀，等主人撫摸。偶爾 能趁著飯菜煮好、家事做完，家人回來前的片刻，躺在沙發上，卻一不小心就陷進 濃稠睡意中。黃昏如一襲誘人的薄被，輕手輕腳覆蓋，放送著催人意志軟化的倦意。 掙扎著醒來時，天光像被突然抽去了一大截亮度，暗下許多。此時的沙發是一列路 中暫停的列車，還不明確的時間是鐵軌鋪排而成的虛線，也許在等待將從遠處疾奔 到來的會車，也許等候此時月台上延遲發車的車輛駛離才能繼續進站，或是等待一 隻於歸途中逗留在鐵軌上野生動物，逃離。」 根據上文，下列選項何者錯誤？', '["沙發是作者繁忙世俗生活中，暫時歇息的停靠站", "主要描寫在傍晚時分，自家客廳的居家生活片段", "誘人的薄被形容沙發給人的慰藉，十分愜意美好", "作者半夢半醒，在恍惚間無法確定接下來的計畫"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "2d4a2c95a108", "answer_pdf_sha1": "f6341680c20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00057', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-13504c0c', 'sub-aboriginal-f7485f85-03', NULL, 'single_choice', '「從前的鐵路便當之所以被懷念，並非便當太好吃，毋寧是一種旅行感所渲染。在出 國還不普遍的年代，火車站月臺就是現代陽關，當火車緩緩啟動，有人輕聲道別， 有人拭淚叮嚀。火車越開越疾，一邊看風景快速奔跑，一邊若有所思地吃便當。當 年那個便當盒帶著離別的身影，復經過記憶的點滴修飾，已編織成一則美麗的動人 傳說。」 根據上文，對於「鐵路便當」的敘述正確的是：', '["一點都不好吃，完全是記憶的作祟", "曾經十分美味，是因為少見的新奇", "帶著越界性質，所以充滿探險滋味", "滋味令人懷念，和記憶的點滴相關"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "2d4a2c95a108", "answer_pdf_sha1": "f6341680c20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00058', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-13504c0c', 'sub-aboriginal-f7485f85-03', NULL, 'single_choice', '「真誠是第一把藝術的鑰匙。知之為知之，不知為不知。真誠的『不懂』，比不真誠 的『懂』，還叫人好受些。最可厭的莫如自以為是，自作解人。有了真誠，才會有虛 心，有了虛心，才肯丟開自己去了解別人，也才能放下虛偽的自尊心去了解自己。 建築在了解自己了解別人上面的愛，才不是盲目的愛。」 下列選項，最合乎本文意旨的是：', '["「自作解人」比「不求甚解」更高明", "了解別人比了解自己，需要更多的真誠", "具備謙遜與學養，藝術家才不致傲慢自是", "專業的藝術批評比不真誠的讚美更叫人難受"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "2d4a2c95a108", "answer_pdf_sha1": "f6341680c20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00059', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-13504c0c', 'sub-aboriginal-f7485f85-03', NULL, 'single_choice', '「醫藥之父希波克拉底（西元前460年－前370年）曾譽接骨木為天然醫藥箱，認為 它是自然界最偉大的治癒植物之一。美洲原住民將其用來調理各種肌膚問題；歐洲 人將它視為生活萬靈丹，大人小孩感冒或換季不適時會在溫涼的接骨木茶裡加入蜂 蜜飲用，舒緩不適感，也是最好的眼睛保養香草之一。還可用來熬煮成果醬、糖漿 和製作甜點。」 根據上文，下列選項何者正確？', '["接骨木被視為天然醫藥箱，因能延年益壽抗老化", "接骨木可應用在醫藥生技、身體保健與甜點食用", "野生的接骨木混合蜂蜜，能有效治療感冒與流感", "最早發現接骨木功效並加以應用的是美洲原住民"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "2d4a2c95a108", "answer_pdf_sha1": "f6341680c20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00060', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-13504c0c', 'sub-aboriginal-f7485f85-03', NULL, 'single_choice', '「撰寫講稿，難的是在於如何精準傳達要藉由致詞場合所釋放的訊息，不只是遣詞用 字必須精準，邏輯鋪陳必須正確，同時還要顧及總統的口語發音，以及總統身分的 高度。除此之外，最要掌握的是文氣，因著場合的不同，總統的致詞或要氣勢磅礴， 或要溫暖動人，除了讓在場的聽眾感受到之外，更必須讓透過書面媒體閱讀的廣大 受眾也能體會得到文字中所包涵的力量。而這也是我常常必須動手修改諸多長官與 學者專家所撰擬的文稿，最主要的原因。」 下列選項，最符合本文意旨的是：', '["總統的講稿，需要特別加強氣勢磅礴的力量", "講稿必須考量場合、對象及口語或書面應用", "文稿的修改，是在檢視是否符合應用文體例", "口語講稿和書面文稿，用詞應該保有一致性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "2d4a2c95a108", "answer_pdf_sha1": "f6341680c20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL)
